    @WebMethod
    public String processXMLData(String xmlPayload) {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);
            factory.setIgnoringElementContentWhitespace(true);
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(new ByteArrayInputStream(xmlPayload.getBytes()));
            
            return processDocument(document);
            
        } catch (ParserConfigurationException | SAXException | IOException e) {
            throw new RuntimeException("Failed to process XML payload", e);
        }
    }
    
    private String processDocument(Document document) {
        Element root = document.getDocumentElement();
        StringBuilder result = new StringBuilder();
        
        processElement(root, result, 0);
        
        return result.toString();
    }
    
    private void processElement(Element element, StringBuilder result, int depth) {
        String indent = "  ".repeat(depth);
        result.append(indent).append("<").append(element.getNodeName()).append(">\n");
        
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            org.w3c.dom.Node node = children.item(i);
            
            if (node.getNodeType() == org.w3c.dom.Node.ELEMENT_NODE) {
                processElement((Element) node, result, depth + 1);
            } else if (node.getNodeType() == org.w3c.dom.Node.TEXT_NODE) {
                String text = node.getTextContent().trim();
                if (!text.isEmpty()) {
                    result.append(indent).append("  ").append(text).append("\n");
                }
            }
        }
        
        result.append(indent).append("</").append(element.getNodeName()).append(">\n");
    }
    
    @WebMethod
    public List<ImportRecord> processLargeXMLPayload(String xmlPayload) {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(new ByteArrayInputStream(xmlPayload.getBytes()));
            
            return extractImportRecords(document);
            
        } catch (ParserConfigurationException | SAXException | IOException e) {
            throw new RuntimeException("Failed to process large XML payload", e);
        }
    }
    
    private List<ImportRecord> extractImportRecords(Document document) {
        List<ImportRecord> records = new ArrayList<>();
        NodeList recordNodes = document.getElementsByTagName("record");
        
        for (int i = 0; i < recordNodes.getLength(); i++) {
            Element recordElement = (Element) recordNodes.item(i);
            ImportRecord record = new ImportRecord();
            
            record.setId(getElementText(recordElement, "id"));
            record.setName(getElementText(recordElement, "name"));
            record.setCategory(getElementText(recordElement, "category"));
            
            NodeList nestedElements = recordElement.getChildNodes();
            for (int j = 0; j < nestedElements.getLength(); j++) {
                org.w3c.dom.Node node = nestedElements.item(j);
                if (node.getNodeType() == org.w3c.dom.Node.ELEMENT_NODE) {
                    Element nestedElement = (Element) node;
                    if ("details".equals(nestedElement.getNodeName())) {
                        record.setDetails(extractDetails(nestedElement));
                    } else if ("metadata".equals(nestedElement.getNodeName())) {
                        record.setMetadata(extractMetadata(nestedElement));
                    }
                }
            }
            
            records.add(record);
        }
        
        return records;
    }
    
    private String getElementText(Element parent, String tagName) {
        NodeList nodes = parent.getElementsByTagName(tagName);
        if (nodes.getLength() > 0) {
            return nodes.item(0).getTextContent();
        }
        return null;
    }
    
    private List<Detail> extractDetails(Element detailsElement) {
        List<Detail> details = new ArrayList<>();
        NodeList detailNodes = detailsElement.getElementsByTagName("detail");
        
        for (int i = 0; i < detailNodes.getLength(); i++) {
            Element detailElement = (Element) detailNodes.item(i);
            Detail detail = new Detail();
            detail.setKey(getElementText(detailElement, "key"));
            detail.setValue(getElementText(detailElement, "value"));
            details.add(detail);
        }
        
        return details;
    }
    
    private List<Metadata> extractMetadata(Element metadataElement) {
        List<Metadata> metadataList = new ArrayList<>();
        NodeList metadataNodes = metadataElement.getElementsByTagName("item");
        
        for (int i = 0; i < metadataNodes.getLength(); i++) {
            Element itemElement = (Element) metadataNodes.item(i);
            Metadata metadata = new Metadata();
            metadata.setField(getElementText(itemElement, "field"));
            metadata.setValue(getElementText(itemElement, "value"));
            metadataList.add(metadata);
        }
        
        return metadataList;
    }
    
